<script>
  $(document).ready(function () {
    const formatNumber = x => x.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');

    const startCounter = ($el, decimalPlaces) => {
      const target = parseFloat($el.text().replace(/,/g, ''));
      $el.text('0'.padEnd(decimalPlaces + 2, '0'));
      $({ count: 0 }).animate({ count: target }, {
        duration: 2500,
        easing: 'swing',
        step: function () {
          $el.text(formatNumber(this.count.toFixed(decimalPlaces)));
        }
      });
    };

    const checkCounters = () => {
      $('.count, .point-count').each(function () {
        const $el = $(this);
        if ($el.offset().top < $(window).scrollTop() + $(window).height() && !$el.data('counted')) {
          const decimals = $el.hasClass('point-count') ? 1 : 0;
          startCounter($el, decimals);
          $el.data('counted', true); // Mark as counted to prevent re-triggering
        }
      });
    };

    $(window).on('scroll', checkCounters);

    checkCounters();
  });
</script>
